#include <iostream>
#include <string>

class Vehicle {
public:
  std::string brand;
  int year;
  Vehicle(std::string b, int y) : brand(b), year(y) {}
  void displayInfo() {
    std::cout << "Brand: " << brand << std::endl;
    std::cout << "Year: " << year << std::endl;
  }
};

class Car : public Vehicle {
public:
  int doors;
  Car(std::string b, int y, int d) : Vehicle(b, y), doors(d) {}
  void displayCarInfo() {
    displayInfo();
    std::cout << "Doors: " << doors << std::endl;
  }
};

int main() {
  Car car("Toyota", 2020, 4);
  car.displayCarInfo();
  return 0;
}
// Output:
// Brand: Toyota
// Year: 2020
// Doors: 4

