#include <string>

class Vehicle {
public:
  virtual void sound() {
    std::cout << "Vehicle makes a sound" << std::endl;
  }
};

class Car : public Vehicle {
public:
  void sound() override {
    std::cout << "Car honks" << std::endl;
  }
};

int main() {
  Vehicle* vehicle = new Car();
  vehicle->sound();
  delete vehicle;
  return 0;
}
// Output:
// Car honks

